# GridUnion namespace naming conventions
# Enforced by CI validation on every DDL statement

ALLOWED_SCHEMA_PATTERNS = {
    'bronze':   r'^bronze_(de|fr|nl|lu)$',           # bronze_{country}
    'silver':   r'^silver_(de|fr|nl|lu)$',           # silver_{country}
    'gold':     r'^gold_[a-z_]+$',                    # gold_{domain}
    'platinum': r'^platinum_[a-z_]+$',                # platinum_{domain}
    'state':    r'^state$',                           # pipeline state tables
    'monitoring': r'^monitoring$',                    # platform metrics
}

ALLOWED_TABLE_PATTERNS = {
    # Tables use snake_case, no abbreviations, no version numbers
    'general': r'^[a-z][a-z0-9_]{2,60}$',
    # Prohibited patterns (caught by CI)
    'prohibited': [
        r'_v\d+$',           # no version suffixes (meter_readings_v2)
        r'_final$',          # no _final suffix
        r'_temp$',           # no _temp (use transient schemas instead)
        r'_backup$',         # no _backup (use Delta time travel)
        r'^tmp_',            # no tmp_ prefix
    ],
}

def validate_fully_qualified_name(fqn: str) -> list[str]:
    """Validate a catalog.schema.table name against GridUnion conventions.

    Returns a list of violation messages (empty = valid).
    """
    parts = fqn.split('.')
    violations = []

    if len(parts) != 3:
        violations.append(f"Expected 3 parts (catalog.schema.table), got {len(parts)}")
        return violations

    catalog, schema, table = parts

    # Catalog must be one of the three environments
    if catalog not in ('gridunion_prod', 'gridunion_staging', 'gridunion_dev'):
        violations.append(f"Invalid catalog: {catalog}")

    # Schema must match one of the allowed patterns
    import re
    schema_valid = any(
        re.match(pattern, schema) 
        for pattern in ALLOWED_SCHEMA_PATTERNS.values()
    )
    if not schema_valid:
        violations.append(f"Invalid schema: {schema}")

    # Table must match general pattern and not match prohibited patterns
    if not re.match(ALLOWED_TABLE_PATTERNS['general'], table):
        violations.append(f"Invalid table name: {table}")
    for prohibited in ALLOWED_TABLE_PATTERNS['prohibited']:
        if re.search(prohibited, table):
            violations.append(f"Prohibited table name pattern: {table} matches {prohibited}")

    return violations

-- Unity Catalog access control for the German Silver schema
-- Only the German DE team can write; everyone else reads

-- Owner team: full access
GRANT ALL PRIVILEGES ON SCHEMA gridunion_prod.silver_de TO `de_germany_team`;

-- Consumer teams: read-only
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `analytics_team`;
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `ml_team`;
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `de_france_team`;  -- cross-country reads

-- Regulatory team: read-only on country-specific schemas
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `regulatory_de_team`;
GRANT SELECT ON SCHEMA gridunion_prod.gold_regulatory TO `regulatory_de_team`;
-- Note: regulatory_de_team has NO access to silver_fr, silver_nl, silver_lu

-- Platform team: admin access for maintenance
GRANT ALL PRIVILEGES ON CATALOG gridunion_prod TO `platform_admin_team`;
